// MARK: - Secure API Client
class SecureAPIClient {
    static let shared = SecureAPIClient()
    
    private init() {}
    
    private func validateDevice() -> Bool {
        guard let deviceToken = UIDevice.current.identifierForVendor else { return false }
        return !deviceToken.uuidString.isEmpty
    }
    
    func fetchStocks(completion: @escaping (Result<[Stock], Error>) -> Void) {
        guard validateDevice() else {
            completion(.failure(NetworkError.deviceValidationFailed))
            return
        }
        
        guard let url = URL(string: "https://api.example.com/stocks") else {
            completion(.failure(NetworkError.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.setValue("Bearer \(getSecureToken())", forHTTPHeaderField: "Authorization")
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else {
                completion(.failure(NetworkError.noData))
                return
            }
            
            do {
                let stocks = try JSONDecoder().decode([Stock].self, from: data)
                completion(.success(stocks))
            } catch {
                completion(.failure(error))
            }
        }.resume()
    }
    
    func executeTrade(_ trade: Trade, completion: @escaping (Result<Trade, Error>) -> Void) {
        guard validateDevice() else {
            completion(.failure(NetworkError.deviceValidationFailed))
            return
        }
        
        guard let url = URL(string: "https://api.example.com/trades") else {
            completion(.failure(NetworkError.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("Bearer \(getSecureToken())", forHTTPHeaderField: "Authorization")
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        do {
            request.httpBody = try JSONEncoder().encode(trade)
        } catch {
            completion(.failure(error))
            return
        }
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else {
                completion(.failure(NetworkError.noData))
                return
            }
            
            do {
                let executedTrade = try JSONDecoder().decode(Trade.self, from: data)
                completion(.success(executedTrade))
            } catch {
                completion(.failure(error))
            }
        }.resume()
    }
    
    private func getSecureToken() -> String {
        // Secure token retrieval with device fingerprinting
        let deviceID = UIDevice.current.identifierForVendor?.uuidString ?? ""
        let timestamp = String(Date().timeIntervalSince1970)
        let combined = deviceID + timestamp
        return SHA256.hash(combined).base64EncodedString()
    }
}

// MARK: - Network Errors
enum NetworkError: Error, LocalizedError {
    case invalidURL
    case noData
    case deviceValidationFailed
    
    var errorDescription: String? {
        switch self {
        case .invalidURL:
            return "Invalid URL"
        case .noData:
            return "No data received"
        case .deviceValidationFailed:
            return "Device validation failed"
        }
    }
}

// MARK: - SHA256 Helper
struct SHA256 {
    static func hash(_ input: String) -> Data {
        guard let data = input.data(using: .utf8) else { return Data() }
        var digest = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        CC_SHA256(data.withUnsafeBytes { $0.baseAddress?.assumingMemoryBound(to: UInt8.self) }, 
                  CC_LONG(data.count), &digest)
        return Data(digest)
    }
}

// MARK: - Trade Execution Service
class TradeExecutionService: ObservableObject {
    @Published var portfolio: [PortfolioItem] = []
    @Published var stocks: [Stock] = []
    @Published var isLoading = false
    @Published var errorMessage: String?
    
    private var cancellables = Set<AnyCancellable>()
    
    func loadPortfolio() {
        // Simulate loading portfolio
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.5) {
            self.portfolio = [
                PortfolioItem(symbol: "AAPL", quantity: 10, averagePrice: 150.0, currentPrice: 155.0),
                PortfolioItem(symbol: "GOOGL", quantity: 5, averagePrice: 2800.0, currentPrice: 2850.0)
            ]
        }
    }
    
    func loadStocks() {
        isLoading = true
        SecureAPIClient.shared.fetchStocks { [weak self] result in
            DispatchQueue.main.async {
                self?.isLoading = false
                switch result {
                case .success(let stocks):
                    self?.stocks = stocks
                case .failure(let error):
                    self?.errorMessage = error.localizedDescription
                }
            }
        }
    }
    
    func executeTrade(symbol: String, quantity: Int, type: TradeType) {
        guard let stock = stocks.first(where: { $0.symbol == symbol }) else { return }
        
        let trade = Trade(
            symbol: symbol,
            quantity: quantity,
            price: stock.currentPrice,
            type: type,
            timestamp: Date()
        )
        
        SecureAPIClient.shared.executeTrade(trade) { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let executedTrade):
                    self?.updatePortfolio(for: executedTrade)
                case .failure(let error):
                    self?.errorMessage = error.localizedDescription
                }
            }
        }
    }
    
    private func updatePortfolio(for trade: Trade) {
        if trade.type == .buy {
            if let index = portfolio.firstIndex(where: { $0.symbol == trade.symbol }) {
                let existing = portfolio[index]
                let totalQuantity = existing.quantity + trade.quantity
                let totalValue = (existing.quantity * existing.averagePrice) + (trade.quantity * trade.price)
                let newAverage = totalValue / Double(totalQuantity)
                
                portfolio[index] = PortfolioItem(
                    symbol: trade.symbol,
                    quantity: totalQuantity,
                    averagePrice: newAverage,
                    currentPrice: existing.currentPrice
                )
            } else {
                portfolio.append(PortfolioItem(
                    symbol: trade.symbol,
                    quantity: trade.quantity,
                    averagePrice: trade.price,
                    currentPrice: trade.price
                ))
            }
        } else {
            if let index = portfolio.firstIndex(where: { $0.symbol == trade.symbol }) {
                let existing = portfolio[index]
                let newQuantity = existing.quantity - trade.quantity
                
                if newQuantity <= 0 {
                    portfolio.remove(at: index)
                } else {
                    portfolio[index] = PortfolioItem(
                        symbol: trade.symbol,
                        quantity: newQuantity,
                        averagePrice: existing.averagePrice,
                        currentPrice: existing.currentPrice
                    )
                }
            }
        }
    }
}

